css:
/* 80mm thermal paper width */
.kot-ticket {
    width: 72mm;
    margin: 0 auto;
    padding: 4mm;
    font-family: "Courier New", Courier, monospace;
    font-size: 12px;
    color: #000;
}

.kot-header {
    text-align: center;
    margin-bottom: 4px;
}

.kot-header h2 {
    font-size: 20px;
    font-weight: 900;
    margin: 0 0 4px 0;
    letter-spacing: 2px;
}

.kot-dashed {
    border-top: 1px dashed #000;
    margin: 6px 0;
}

.kot-meta {
    margin: 4px 0;
}

.kot-row {
    display: flex;
    justify-content: space-between;
    margin: 2px 0;
    font-size: 11px;
}

.kot-label {
    font-weight: 700;
}

.kot-value {
    text-align: right;
}

.kot-bold {
    font-weight: 900;
}

.kot-items {
    width: 100%;
    border-collapse: collapse;
    margin: 4px 0;
}

.kot-item-head {
    font-size: 11px;
    font-weight: 700;
    padding: 4px 2px;
    border-bottom: 1px solid #000;
}

.kot-item-cell {
    padding: 5px 2px;
    border-bottom: 1px dashed #ccc;
    vertical-align: top;
}

.kot-item-name {
    font-size: 14px;
    font-weight: 700;
    text-align: left;
}

.kot-item-qty {
    font-size: 18px;
    font-weight: 900;
    text-align: center;
    min-width: 30px;
}

.kot-total-row {
    display: flex;
    justify-content: space-between;
    font-size: 12px;
    font-weight: 700;
    padding: 4px 0;
}

.kot-footer {
    text-align: center;
    font-size: 10px;
    margin-top: 4px;
}

.kot-footer p {
    margin: 2px 0;
}

@media print {
    @page {
        size: 80mm auto;
        margin: 0;
    }
    body {
        margin: 0;
        padding: 0;
    }
    .kot-ticket {
        width: 100%;
    }
}
